// ── Support Tickets (15) — New model ───────────
function makeTimeline(ticketId: string, subject: string): TimelineEntry[] {
  return [
    { id: `TL_${ticketId}_1`, type: TimelineEventType.SYSTEM, content: `Ticket created: ${subject}`, user_id: null, created_at: new Date(Date.now() - 86400000 * 3).toISOString() },
  ];
}

function slaDeadline(hoursFromNow: number): string {
  return new Date(Date.now() + hoursFromNow * 3600000).toISOString();
}

