// ── Helper Functions ───────────────────────────
export function getCalendarEventsForEntity(entityType: EntityType, entityId: string): CalendarEvent[] {
  return seedCalendarEvents.filter(e => e.entity_type === entityType && e.entity_id === entityId);
}

export function getNextUpcomingEvent(entityType: EntityType, entityId: string): CalendarEvent | null {
  const upcoming = seedCalendarEvents
    .filter(e => e.entity_type === entityType && e.entity_id === entityId && e.status === CalendarEventStatus.UPCOMING)
    .sort((a, b) => new Date(a.scheduled_at).getTime() - new Date(b.scheduled_at).getTime());
  return upcoming[0] ?? null;
}

export function getAccountName(accountId: string | null): string {
  if (!accountId) return '—';
  return seedAccounts.find(a => a.account_id === accountId)?.account_name ?? accountId;
}
